{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/order.json",
  "name": "dev.ucp.shopping.order",
  "title": "Order",
  "description": "Order schema with line items, buyer-facing fulfillment expectations, and event logs.",
  "$defs": {
    "platform_schema": {
      "title": "Platform Order Schema",
      "description": "Platform's order capability configuration.",
      "type": "object",
      "required": [
        "webhook_url"
      ],
      "properties": {
        "webhook_url": {
          "type": "string",
          "format": "uri",
          "description": "URL where merchant sends order lifecycle events (webhooks)."
        }
      }
    }
  },
  "type": "object",
  "required": [
    "ucp",
    "id",
    "checkout_id",
    "permalink_url",
    "line_items",
    "fulfillment",
    "currency",
    "totals"
  ],
  "properties": {
    "ucp": {
      "$ref": "../ucp.json#/$defs/response_order_schema"
    },
    "id": {
      "type": "string",
      "description": "Unique order identifier."
    },
    "label": {
      "type": "string",
      "description": "Human-readable label for identifying the order. MUST only be provided by the business."
    },
    "checkout_id": {
      "type": "string",
      "description": "Associated checkout ID for reconciliation."
    },
    "permalink_url": {
      "type": "string",
      "format": "uri",
      "description": "Permalink to access the order on merchant site."
    },
    "line_items": {
      "type": "array",
      "items": {
        "$ref": "types/order_line_item.json"
      },
      "description": "Line items representing what was purchased — can change post-order via edits or exchanges."
    },
    "fulfillment": {
      "type": "object",
      "properties": {
        "expectations": {
          "type": "array",
          "items": {
            "$ref": "types/expectation.json"
          },
          "description": "Buyer-facing groups representing when/how items will be delivered. Can be split, merged, or adjusted post-order."
        },
        "events": {
          "type": "array",
          "items": {
            "$ref": "types/fulfillment_event.json"
          },
          "description": "Append-only event log of actual shipments. Each event references line items by ID."
        }
      },
      "description": "Fulfillment data: buyer expectations and what actually happened."
    },
    "adjustments": {
      "type": "array",
      "items": {
        "$ref": "types/adjustment.json"
      },
      "description": "Post-order events (refunds, returns, credits, disputes, cancellations, etc.) that exist independently of fulfillment."
    },
    "currency": {
      "type": "string",
      "description": "ISO 4217 currency code. MUST match the currency from the originating checkout session.",
      "ucp_request": "omit"
    },
    "totals": {
      "$ref": "types/totals.json",
      "description": "Different totals for the order."
    },
    "messages": {
      "type": "array",
      "items": {
        "$ref": "types/message.json"
      },
      "description": "Business outcome messages (errors, warnings, informational). Present when the business needs to communicate status or issues to the platform."
    },
    "attribution": {
      "$ref": "types/attribution.json",
      "description": "Snapshot of the attribution associated with the originating checkout. Read-only on the order.",
      "ucp_request": "omit"
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/types/card_credential.json",
  "title": "Card Credential",
  "description": "A card credential containing sensitive payment card details including raw Primary Account Numbers (PANs). This credential type MUST NOT be used for checkout, only with payment handlers that tokenize or encrypt credentials. CRITICAL: Both parties handling CardCredential (sender and receiver) MUST be PCI DSS compliant. Transmission MUST use HTTPS/TLS with strong cipher suites.",
  "allOf": [
    {
      "$ref": "payment_credential.json"
    },
    {
      "type": "object",
      "required": [
        "type",
        "card_number_type"
      ],
      "properties": {
        "type": {
          "const": "card",
          "description": "The credential type identifier for card credentials."
        },
        "card_number_type": {
          "type": "string",
          "enum": [
            "fpan",
            "network_token",
            "dpan"
          ],
          "description": "The type of card number. Network tokens are preferred with fallback to FPAN. See PCI Scope for more details."
        },
        "number": {
          "type": "string",
          "description": "Card number.",
          "examples": [
            "4242424242424242"
          ]
        },
        "expiry_month": {
          "type": "integer",
          "description": "The month of the card's expiration date (1-12)."
        },
        "expiry_year": {
          "type": "integer",
          "description": "The year of the card's expiration date."
        },
        "name": {
          "type": "string",
          "description": "Cardholder name.",
          "examples": [
            "Jane Doe"
          ]
        },
        "cvc": {
          "type": "string",
          "maxLength": 4,
          "description": "Card CVC number.",
          "examples": [
            "223"
          ]
        },
        "cryptogram": {
          "type": "string",
          "description": "Cryptogram provided with network tokens.",
          "examples": [
            "gXc5UCLnM6ckD7pjM1TdPA=="
          ]
        },
        "eci_value": {
          "type": "string",
          "description": "Electronic Commerce Indicator / Security Level Indicator provided with network tokens.",
          "examples": [
            "07"
          ]
        }
      }
    }
  ]
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/payment_handler.json",
  "title": "Payment Handler",
  "description": "Schema for UCP payment handlers. Handlers define how payment instruments are processed.",

  "$defs": {
    "base": {
      "allOf": [
        { "$ref": "ucp.json#/$defs/entity" },
        {
          "type": "object",
          "required": ["id"]
        },
        {
          "type": "object",
          "properties": {
            "available_instruments": {
              "type": "array",
              "items": { "$ref": "shopping/types/available_payment_instrument.json" },
              "description": "Instrument types this handler supports, with optional constraints. When absent, every instrument should be considered available.",
              "minItems": 1
            }
          }
        }
      ]
    },

    "platform_schema": {
      "title": "Payment Handler (Platform Schema)",
      "description": "Platform declaration for discovery profiles. May include partial config state required for discovery.",
      "allOf": [{ "$ref": "#/$defs/base" }, { "required": ["spec", "schema"] }]
    },

    "business_schema": {
      "title": "Payment Handler (Business Schema)",
      "description": "Business declaration for discovery profiles. May include partial config state required for discovery.",
      "allOf": [{ "$ref": "#/$defs/base" }]
    },

    "response_schema": {
      "title": "Payment Handler (Response Schema)",
      "description": "Handler reference in responses. May include full config state for runtime usage of the handler.",
      "allOf": [{ "$ref": "#/$defs/base" }]
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/types/message_warning.json",
  "title": "Message Warning",
  "type": "object",
  "required": [
    "type",
    "code",
    "content"
  ],
  "properties": {
    "type": {
      "type": "string",
      "const": "warning",
      "description": "Message type discriminator."
    },
    "path": {
      "type": "string",
      "description": "JSONPath (RFC 9535) to related field (e.g., $.line_items[0])."
    },
    "code": {
      "$ref": "warning_code.json"
    },
    "content": {
      "type": "string",
      "description": "Human-readable warning message that MUST be displayed."
    },
    "content_type": {
      "type": "string",
      "enum": [
        "plain",
        "markdown"
      ],
      "default": "plain",
      "description": "Content format, default = plain."
    },
    "presentation": {
      "type": "string",
      "default": "notice",
      "description": "Rendering contract for this warning. 'notice' (default): platform MUST display, MAY dismiss. 'disclosure': platform MUST display in proximity to the path-referenced component, MUST NOT hide or auto-dismiss. See specification for full contract."
    },
    "image_url": {
      "type": "string",
      "format": "uri",
      "description": "URL to a required visual element (e.g., warning symbol, energy class label)."
    },
    "url": {
      "type": "string",
      "format": "uri",
      "description": "Reference URL for more information (e.g., regulatory site, registry entry, policy page)."
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/types/search_filters.json",
  "title": "Search Filters",
  "description": "Filter criteria to narrow search results. All specified filters combine with AND logic.",
  "type": "object",
  "properties": {
    "categories": {
      "type": "array",
      "items": { "type": "string" },
      "description": "Filter by product categories (OR logic — matches products in any listed categories). Values match against the value field in product category entries. Valid values can be discovered from the categories field in search results, merchant documentation, or standard taxonomies that businesses may align with."
    },
    "price": {
      "$ref": "price_filter.json"
    }
  },
  "additionalProperties": true
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/types/search_filters.json",
  "title": "Search Filters",
  "description": "Filter criteria to narrow search results. All specified filters combine with AND logic.",
  "type": "object",
  "properties": {
    "categories": {
      "type": "array",
      "items": { "type": "string" },
      "description": "Filter by product categories (OR logic — matches products in any listed categories). Values match against the value field in product category entries. Valid values can be discovered from the categories field in search results, merchant documentation, or standard taxonomies that businesses may align with."
    },
    "price": {
      "$ref": "price_filter.json"
    }
  },
  "additionalProperties": true
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/types/product.json",
  "title": "Product",
  "description": "A product in the catalog with variants and options.",
  "type": "object",
  "required": [
    "id",
    "title",
    "description",
    "price_range",
    "variants"
  ],
  "properties": {
    "id": {
      "type": "string",
      "description": "Global ID (GID) uniquely identifying this product."
    },
    "handle": {
      "type": "string",
      "description": "URL-safe slug for SEO-friendly URLs (e.g., 'blue-runner-pro'). Use id for stable API references."
    },
    "title": {
      "type": "string",
      "description": "Product title."
    },
    "description": {
      "$ref": "description.json",
      "description": "Product description in one or more formats."
    },
    "url": {
      "type": "string",
      "format": "uri",
      "description": "Canonical product page URL."
    },
    "categories": {
      "type": "array",
      "items": {
        "$ref": "category.json"
      },
      "description": "Product categories with optional taxonomy identifiers."
    },
    "price_range": {
      "$ref": "price_range.json",
      "description": "Price range across all variants."
    },
    "list_price_range": {
      "$ref": "price_range.json",
      "description": "List price range before discounts (for strikethrough display)."
    },
    "media": {
      "type": "array",
      "items": {
        "$ref": "media.json"
      },
      "description": "Product media (images, videos, 3D models). First item is the featured media for listings."
    },
    "options": {
      "type": "array",
      "items": {
        "$ref": "product_option.json"
      },
      "description": "Product options (Size, Color, etc.)."
    },
    "variants": {
      "type": "array",
      "items": {
        "$ref": "variant.json"
      },
      "minItems": 1,
      "description": "Purchasable variants of this product. First item is the featured variant for listings."
    },
    "rating": {
      "$ref": "rating.json",
      "description": "Aggregate product rating."
    },
    "tags": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Product tags for categorization and search."
    },
    "metadata": {
      "type": "object",
      "description": "Business-defined custom data extending the standard product model."
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/types/variant.json",
  "title": "Variant",
  "description": "A purchasable variant of a product with specific option selections.",
  "type": "object",
  "required": [
    "id",
    "title",
    "description",
    "price"
  ],
  "properties": {
    "id": {
      "type": "string",
      "description": "Global ID (GID) uniquely identifying this variant. Used as item.id in checkout."
    },
    "sku": {
      "type": "string",
      "description": "Business-assigned identifier for inventory and fulfillment."
    },
    "barcodes": {
      "type": "array",
      "items": {
        "type": "object",
        "required": ["type", "value"],
        "properties": {
          "type": {
            "type": "string",
            "description": "Barcode standard. Well-known values: UPC, EAN, ISBN, GTIN, JAN."
          },
          "value": {
            "type": "string",
            "description": "Barcode value."
          }
        }
      },
      "description": "Industry-standard product identifiers for cross-reference and correlation."
    },
    "handle": {
      "type": "string",
      "description": "URL-safe variant handle/slug."
    },
    "title": {
      "type": "string",
      "description": "Variant display title (e.g., 'Blue / Large')."
    },
    "description": {
      "$ref": "description.json",
      "description": "Variant description in one or more formats."
    },
    "url": {
      "type": "string",
      "format": "uri",
      "description": "Canonical variant page URL."
    },
    "categories": {
      "type": "array",
      "items": {
        "$ref": "category.json"
      },
      "description": "Variant categories with optional taxonomy identifiers."
    },
    "price": {
      "$ref": "price.json",
      "description": "Current selling price."
    },
    "list_price": {
      "$ref": "price.json",
      "description": "List price before discounts (for strikethrough display)."
    },
    "unit_price": {
      "type": "object",
      "description": "Price per standard unit of measurement. MAY be omitted when unit pricing does not apply.",
      "required": ["amount", "currency", "measure", "reference"],
      "properties": {
        "amount": {
          "$ref": "amount.json",
          "description": "Unit price in ISO 4217 minor units. Business MUST return precomputed unit price value: (variant.price / measure.value) * reference.value."
        },
        "currency": {
          "type": "string",
          "pattern": "^[A-Z]{3}$",
          "description": "ISO 4217 currency code."
        },
        "measure": {
          "type": "object",
          "description": "Product quantity in packaging (e.g., 750ml bottle).",
          "required": ["value", "unit"],
          "properties": {
            "value": { "type": "number", "description": "Package quantity." },
            "unit": { "type": "string", "description": "Unit of measurement." }
          }
        },
        "reference": {
          "type": "object",
          "description": "Denominator for unit price display (e.g., per 100ml, per 1kg).",

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/types/totals.json",
  "title": "Totals",
  "description": "Pricing breakdown provided by the business. MUST contain exactly one subtotal and one total entry. Detail types (tax, fee, discount, fulfillment) may appear multiple times for itemization. Platforms MUST render all entries in order using display_text and amount.",
  "type": "array",
  "items": {
    "allOf": [
      {
        "$ref": "total.json"
      },
      {
        "type": "object",
        "properties": {
          "lines": {
            "type": "array",
            "items": {
              "type": "object",
              "required": [
                "display_text",
                "amount"
              ],
              "properties": {
                "display_text": {
                  "type": "string",
                  "description": "Human-readable label for this sub-line."
                },
                "amount": {
                  "$ref": "signed_amount.json"
                }
              },
              "description": "Sub-line entry. Additional metadata MAY be included."
            },
            "description": "Optional itemized breakdown. The parent entry is always rendered; lines are supplementary. Sum of line amounts MUST equal the parent entry amount.",
            "ucp_request": "omit"
          }
        }
      },
      {
        "if": {
          "properties": {
            "type": { "not": { "enum": ["subtotal", "items_discount", "discount", "fulfillment", "tax", "fee", "total"] } }
          },
          "required": ["type"]
        },
        "then": { "required": ["display_text"] }
      }
    ]
  },
  "allOf": [
    {
      "contains": { "properties": { "type": { "const": "subtotal" } }, "required": ["type"] },
      "minContains": 1,
      "maxContains": 1
    },
    {
      "contains": { "properties": { "type": { "const": "total" } }, "required": ["type"] },
      "minContains": 1,
      "maxContains": 1
    }
  ]
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/types/item.json",
  "title": "Item",
  "type": "object",
  "required": [
    "id",
    "title",
    "price"
  ],
  "properties": {
    "id": {
      "type": "string",
      "description": "The product identifier, often the SKU, required to resolve the product details associated with this line item. Should be recognized by both the Platform, and the Business."
    },
    "title": {
      "type": "string",
      "description": "Product title.",
      "ucp_request": "omit"
    },
    "price": {
      "$ref": "amount.json",
      "description": "Unit price in ISO 4217 minor units.",
      "ucp_request": "omit"
    },
    "image_url": {
      "type": "string",
      "description": "Product image URI.",
      "format": "uri",
      "ucp_request": "omit"
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/cart.json",
  "name": "dev.ucp.shopping.cart",
  "title": "Cart",
  "description": "Shopping cart with estimated pricing before checkout. Lightweight pre-purchase exploration with no payment info or complex status states.",
  "$defs": {
    "checkout": {
      "title": "Checkout with Cart",
      "description": "Checkout extended with cart capability. Adds cart_id to create_checkout for cart-to-checkout conversion.",
      "allOf": [
        {
          "$ref": "checkout.json"
        },
        {
          "type": "object",
          "properties": {
            "cart_id": {
              "type": "string",
              "description": "Cart ID to convert to checkout. Business MUST use cart contents (line_items, context, buyer) and MUST ignore overlapping fields in checkout payload.",
              "ucp_request": {
                "create": "optional",
                "update": "omit"
              }
            }
          }
        }
      ]
    }
  },
  "type": "object",
  "required": [
    "ucp",
    "id",
    "line_items",
    "currency",
    "totals"
  ],
  "additionalProperties": true,
  "properties": {
    "ucp": {
      "$ref": "../ucp.json#/$defs/response_cart_schema",
      "ucp_request": "omit"
    },
    "id": {
      "type": "string",
      "description": "Unique cart identifier.",
      "ucp_request": {
        "create": "omit",
        "update": "required"
      }
    },
    "line_items": {
      "type": "array",
      "items": {
        "$ref": "types/line_item.json"
      },
      "description": "Cart line items. Same structure as checkout. Full replacement on update.",
      "ucp_request": {
        "create": "required",
        "update": "required"
      }
    },
    "context": {
      "$ref": "types/context.json",
      "description": "Buyer signals for localization (country, region, postal_code). Merchant uses for pricing, availability, currency. Falls back to geo-IP if omitted.",
      "ucp_request": {
        "create": "optional",
        "update": "optional"
      }
    },
    "signals": {
      "$ref": "types/signals.json",
      "ucp_request": {
        "create": "optional",
        "update": "optional"
      }
    },
    "attribution": {
      "$ref": "types/attribution.json",
      "ucp_request": {
        "create": "optional",
        "update": "optional"
      }
    },
    "buyer": {
      "$ref": "types/buyer.json",
      "description": "Optional buyer information for personalized estimates.",
      "ucp_request": {
        "create": "optional",
        "update": "optional"
      }
    },
    "currency": {
      "type": "string",
      "description": "ISO 4217 currency code. Determined by merchant based on context or geo-IP.",
      "ucp_request": "omit"
    },
    "totals": {
      "$ref": "types/totals.json",
      "description": "Estimated cost breakdown. May be partial if shipping/tax not yet calculable.",
      "ucp_request": "omit"
    },
    "messages": {
      "type": "array",
      "items": {
        "$ref": "types/message.json"
      },
      "description": "Validation messages, warnings, or informational notices.",
      "ucp_request": "omit"
    },
    "links": {
      "type": "array",
      "items": {
        "$ref": "types/link.json"
      },
      "description": "Optional merchant links (policies, FAQs).",
      "ucp_request": "omit"
    },
    "continue_url": {
      "type": "string",
      "format": "uri",
      "description": "URL for cart handoff and session recovery. Enables sharing and human-in-the-loop flows.",
      "ucp_request": "omit"
    },
    "expires_at": {
      "type": "string",
      "format": "date-time",
      "description": "Cart expiry timestamp (RFC 3339). Optional.",
      "ucp_request": "omit"
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/types/line_item.json",
  "title": "Line Item",
  "type": "object",
  "description": "Line item object. Expected to use the currency of the parent object.",
  "required": [
    "id",
    "item",
    "quantity",
    "totals"
  ],
  "properties": {
    "id": {
      "type": "string",
      "ucp_request": {
        "create": "omit",
        "update": "optional"
      }
    },
    "item": {
      "$ref": "item.json"
    },
    "quantity": {
      "type": "integer",
      "description": "Quantity of the item being purchased.",
      "minimum": 1
    },
    "totals": {
      "type": "array",
      "items": {
        "$ref": "total.json"
      },
      "description": "Line item totals breakdown.",
      "ucp_request": "omit"
    },
    "parent_id": {
      "type": "string",
      "description": "Parent line item identifier for any nested structures.",
      "ucp_request": {
        "create": "omit",
        "update": "optional"
      }
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/types/adjustment.json",
  "title": "Adjustment",
  "description": "Post-order event that exists independently of fulfillment. Typically represents money movements but can be any post-order change. Polymorphic type that can optionally reference line items.",
  "type": "object",
  "required": [
    "id",
    "type",
    "occurred_at",
    "status"
  ],
  "properties": {
    "id": {
      "type": "string",
      "description": "Adjustment event identifier."
    },
    "type": {
      "type": "string",
      "description": "Type of adjustment (open string). Typically money-related like: refund, return, credit, price_adjustment, dispute, cancellation. Can be any value that makes sense for the merchant's business."
    },
    "occurred_at": {
