{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/types/total.json",
  "title": "Total",
  "description": "A cost breakdown entry with a category, amount, and optional display text.",
  "type": "object",
  "required": [
    "type",
    "amount"
  ],
  "properties": {
    "type": {
      "type": "string",
      "description": "Cost category. Well-known values: subtotal, items_discount, discount, fulfillment, tax, fee, total. Businesses MAY use additional values.",
      "ucp_request": "omit"
    },
    "display_text": {
      "type": "string",
      "description": "Text to display against the amount. Should reflect appropriate method (e.g., 'Shipping', 'Delivery').",
      "ucp_request": "omit"
    },
    "amount": {
      "$ref": "signed_amount.json",
      "ucp_request": "omit"
    }
  },
  "allOf": [
    {
      "if": { "properties": { "type": { "enum": ["discount", "items_discount"] } }, "required": ["type"] },
      "then": { "properties": { "amount": { "exclusiveMaximum": 0 } } }
    },
    {
      "if": { "properties": { "type": { "enum": ["subtotal", "fulfillment", "tax", "fee"] } }, "required": ["type"] },
      "then": { "properties": { "amount": { "minimum": 0 } } }
    }
  ]
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/types/totals.json",
  "title": "Totals",
  "description": "Pricing breakdown provided by the business. MUST contain exactly one subtotal and one total entry. Detail types (tax, fee, discount, fulfillment) may appear multiple times for itemization. Platforms MUST render all entries in order using display_text and amount.",
  "type": "array",
  "items": {
    "allOf": [
      {
        "$ref": "total.json"
      },
      {
        "type": "object",
        "properties": {
          "lines": {
            "type": "array",
            "items": {
              "type": "object",
              "required": [
                "display_text",
                "amount"
              ],
              "properties": {
                "display_text": {
                  "type": "string",
                  "description": "Human-readable label for this sub-line."
                },
                "amount": {
                  "$ref": "signed_amount.json"
                }
              },
              "description": "Sub-line entry. Additional metadata MAY be included."
            },
            "description": "Optional itemized breakdown. The parent entry is always rendered; lines are supplementary. Sum of line amounts MUST equal the parent entry amount.",
            "ucp_request": "omit"
          }
        }
      },
      {
        "if": {
          "properties": {
            "type": { "not": { "enum": ["subtotal", "items_discount", "discount", "fulfillment", "tax", "fee", "total"] } }
          },
          "required": ["type"]
        },
        "then": { "required": ["display_text"] }
      }
    ]
  },
  "allOf": [
    {
      "contains": { "properties": { "type": { "const": "subtotal" } }, "required": ["type"] },
      "minContains": 1,
      "maxContains": 1
    },
    {
      "contains": { "properties": { "type": { "const": "total" } }, "required": ["type"] },
      "minContains": 1,
      "maxContains": 1
    }
  ]
}

/**
 * The base-derived rule ids — DERIVED from the twin's `base` field via the
 * registry (not hand-listed), so it cannot drift. Any finding these rules emit
 * MUST carry the U1 provisional marker ({@link makeFeeFinding} enforces it).
 */
export const BASE_DERIVED_RULE_IDS: ReadonlySet<string> = new Set(
  FEE_RULES.filter((r) => r.base !== undefined).map((r) => r.id),
);

// ── Typed predicates (pure, integer-cents; no float money, no clock) ──────────

/**
 * Per-order cap predicate (a-1 / b-1 / c-1 / d-2): the charged amount exceeds
 * capPct% of the order's purchase price. Integer math: amount*100 > capPct*base
 * (equality is AT the cap, i.e. compliant).
 */
export function perOrderCapExceeded(
  amountCents: number,
  purchasePriceCents: number,
  capPct: number,
): boolean {
  return amountCents * 100 > capPct * purchasePriceCents;
}

/**
 * Monthly-average cap predicate (a-2 / b-2 / d-3): the month's summed fees for a
 * category exceed capPct% of the month's summed purchase price across ALL orders
 * (the twin's `sum_purchase_price_all_orders_in_calendar_month` base).
 */
export function monthlyAverageExceeded(
  sumFeesCents: number,
  sumPurchasePriceCents: number,
  capPct: number,
): boolean {
  return sumFeesCents * 100 > capPct * sumPurchasePriceCents;
}

