{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/types/variant.json",
  "title": "Variant",
  "description": "A purchasable variant of a product with specific option selections.",
  "type": "object",
  "required": [
    "id",
    "title",
    "description",
    "price"
  ],
  "properties": {
    "id": {
      "type": "string",
      "description": "Global ID (GID) uniquely identifying this variant. Used as item.id in checkout."
    },
    "sku": {
      "type": "string",
      "description": "Business-assigned identifier for inventory and fulfillment."
    },
    "barcodes": {
      "type": "array",
      "items": {
        "type": "object",
        "required": ["type", "value"],
        "properties": {
          "type": {
            "type": "string",
            "description": "Barcode standard. Well-known values: UPC, EAN, ISBN, GTIN, JAN."
          },
          "value": {
            "type": "string",
            "description": "Barcode value."
          }
        }
      },
      "description": "Industry-standard product identifiers for cross-reference and correlation."
    },
    "handle": {
      "type": "string",
      "description": "URL-safe variant handle/slug."
    },
    "title": {
      "type": "string",
      "description": "Variant display title (e.g., 'Blue / Large')."
    },
    "description": {
      "$ref": "description.json",
      "description": "Variant description in one or more formats."
    },
    "url": {
      "type": "string",
      "format": "uri",
      "description": "Canonical variant page URL."
    },
    "categories": {
      "type": "array",
      "items": {
        "$ref": "category.json"
      },
      "description": "Variant categories with optional taxonomy identifiers."
    },
    "price": {
      "$ref": "price.json",
      "description": "Current selling price."
    },
    "list_price": {
      "$ref": "price.json",
      "description": "List price before discounts (for strikethrough display)."
    },
    "unit_price": {
      "type": "object",
      "description": "Price per standard unit of measurement. MAY be omitted when unit pricing does not apply.",
      "required": ["amount", "currency", "measure", "reference"],
      "properties": {
        "amount": {
          "$ref": "amount.json",
          "description": "Unit price in ISO 4217 minor units. Business MUST return precomputed unit price value: (variant.price / measure.value) * reference.value."
        },
        "currency": {
          "type": "string",
          "pattern": "^[A-Z]{3}$",
          "description": "ISO 4217 currency code."
        },
        "measure": {
          "type": "object",
          "description": "Product quantity in packaging (e.g., 750ml bottle).",
          "required": ["value", "unit"],
          "properties": {
            "value": { "type": "number", "description": "Package quantity." },
            "unit": { "type": "string", "description": "Unit of measurement." }
          }
        },
        "reference": {
          "type": "object",
          "description": "Denominator for unit price display (e.g., per 100ml, per 1kg).",

        },
        "preferences": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "Option names in relaxation priority order. When no exact variant matches all selections, the server drops options from the end of this list first. E.g., ['Color', 'Size'] keeps Color and relaxes Size."
        },
        "filters": {
          "$ref": "types/search_filters.json",
          "description": "Filter criteria to narrow returned variants. All specified filters combine with AND logic."
        },
        "context": {
          "$ref": "types/context.json"
        },
        "signals": {
          "$ref": "types/signals.json"
        },
        "attribution": {
          "$ref": "types/attribution.json"
        }
      }
    },
    "detail_product": {
      "description": "A product in a get_product response, extended with effective selections and availability signals on option values.",
      "type": "object",
      "allOf": [{ "$ref": "types/product.json" }],
      "properties": {
        "selected": {
          "type": "array",
          "items": { "$ref": "types/selected_option.json" },
          "description": "Effective option selections that anchor the featured variant and availability signals. Required when the product has configurable options; may be empty or omitted for products with no option axes."
        },
        "options": {
          "type": "array",
          "items": {
            "type": "object",
            "required": ["name", "values"],
            "properties": {
              "name": { "type": "string" },
              "values": {
                "type": "array",
                "items": { "$ref": "types/detail_option_value.json" },
                "minItems": 1
              }
            }
          },
          "description": "Product options with availability signals relative to the effective selections."
        }
      }
    },
    "get_product_response": {
      "type": "object",
      "required": [
        "ucp",
        "product"
      ],
      "properties": {
        "ucp": {
          "$ref": "../ucp.json#/$defs/response_catalog_schema"
        },
        "product": {
          "$ref": "#/$defs/detail_product",
          "description": "The requested product with full detail. Singular — this is a single-resource operation."
        },
        "messages": {
          "type": "array",
          "items": {
            "$ref": "types/message.json"
          },
          "description": "Warnings or informational messages about the product (e.g., price recently changed, limited availability)."
        }
      }
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/catalog_lookup.json",
  "name": "dev.ucp.shopping.catalog.lookup",
  "title": "Catalog Lookup",
  "description": "Product/variant lookup by identifier. Supports batch retrieval (lookup_catalog) and single-product detail (get_product).",
  "type": "object",
  "$defs": {
    "lookup_variant": {
      "description": "Variant with required correlation metadata for lookup responses.",
      "allOf": [
        { "$ref": "types/variant.json" },
        {
          "required": ["inputs"],
          "properties": {
            "inputs": {
              "type": "array",
              "items": { "$ref": "types/input_correlation.json" },
              "minItems": 1,
              "description": "Which request identifiers resolved to this variant, and how. Each entry maps a request ID to its match type."
            }
          }
        }
      ]
    },
    "lookup_request": {
      "type": "object",
      "description": "Request body for catalog lookup.",
      "required": ["ids"],
      "properties": {
        "ids": {
          "type": "array",
          "items": { "type": "string" },
          "minItems": 1,
          "description": "Identifiers to lookup. Implementations MUST support product ID and variant ID; MAY support secondary identifiers (SKU, handle, etc.)."
        },
        "filters": {
          "$ref": "types/search_filters.json",
          "description": "Filter criteria to narrow returned products and variants. All specified filters combine with AND logic."
        },
        "context": {
          "$ref": "types/context.json"
        },
        "signals": {
          "$ref": "types/signals.json"
        },
        "attribution": {
          "$ref": "types/attribution.json"
        }
      }
    },
    "lookup_response": {
      "type": "object",
      "required": [
        "ucp",
        "products"
      ],
      "properties": {
