{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/types/signals.json",
  "title": "Signals",
  "description": "Environment data provided by the platform to support authorization and abuse prevention. Values MUST NOT be buyer-asserted claims — platforms provide signals based on direct observation or independently verifiable third-party attestations. All signal keys MUST use reverse-domain naming to ensure provenance and prevent collisions when multiple extensions contribute to the shared namespace.",
  "type": "object",
  "propertyNames": {
    "pattern": "^[a-z][a-z0-9]*(?:\\.[a-z][a-z0-9_]*)+$",
    "description": "Reverse-domain identifier (e.g., dev.ucp.buyer_ip, com.example.device_id)."
  },
  "properties": {
    "dev.ucp.buyer_ip": {
      "type": "string",
      "description": "Client's IP address (IPv4 or IPv6)."
    },
    "dev.ucp.user_agent": {
      "type": "string",
      "description": "Client's HTTP User-Agent header or equivalent."
    }
  },
  "additionalProperties": true
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/types/context.json",
  "title": "Context",
  "description": "Provisional buyer signals for relevance and localization—not authoritative data. Businesses SHOULD use these values when verified inputs (e.g., shipping address) are absent, and MAY ignore or down-rank them if inconsistent with higher-confidence signals (authenticated account, risk detection) or regulatory constraints (export controls). Eligibility and policy enforcement MUST occur at checkout time using binding transaction data. Context SHOULD be non-identifying and can be disclosed progressively—coarse signals early, finer resolution as the session progresses. Higher-resolution data (shipping address, billing address) supersedes context.",
  "type": "object",
  "additionalProperties": true,
  "properties": {
    "address_country": {
      "type": "string",
      "description": "The country. Recommended to be in 2-letter ISO 3166-1 alpha-2 format, for example \"US\". For backward compatibility, a 3-letter ISO 3166-1 alpha-3 country code such as \"SGP\" or a full country name such as \"Singapore\" can also be used. Optional hint for market context (currency, availability, pricing)—higher-resolution data (e.g., shipping address) supersedes this value."
    },
    "address_region": {
      "type": "string",
      "description": "The region in which the locality is, and which is in the country. For example, California or another appropriate first-level Administrative division. Optional hint for progressive localization—higher-resolution data (e.g., shipping address) supersedes this value."
    },
    "postal_code": {
      "type": "string",
      "description": "The postal code. For example, 94043. Optional hint for regional refinement—higher-resolution data (e.g., shipping address) supersedes this value."
    },
    "intent": {
      "type": "string",
      "description": "Background context describing buyer's intent (e.g., 'looking for a gift under $50', 'need something durable for outdoor use'). Informs relevance, recommendations, and personalization."
    },
    "language": {
      "type": "string",
      "description": "Preferred language for content. Use IETF BCP 47 language tags (e.g., 'en', 'fr-CA', 'zh-Hans'). For REST, equivalent to Accept-Language header—platforms SHOULD fall back to Accept-Language when this field is absent; when provided, overrides Accept-Language. Businesses MAY return content in a different language if unavailable."
    },
    "currency": {
      "type": "string",
      "description": "Preferred currency (ISO 4217, e.g., 'EUR', 'USD'). Businesses determine presentment currency from context and authoritative signals; this hint MAY inform selection in multi-currency markets. Also serves as the denomination for price filter values — platforms SHOULD include this field when sending price filters. Response prices include explicit currency confirming the resolution."
    },
    "eligibility": {
      "type": "array",
      "description": "Buyer claims about eligible benefits such as loyalty membership, payment instrument perks, and similar. Recognized claims MAY inform the Business response (e.g., member-only product availability, adjusted pricing in catalog, provisional discounts at cart or checkout). Businesses MUST ignore unrecognized values without error. Values MUST use reverse-domain naming (e.g., 'com.example.loyalty_gold', 'org.school.student') and MUST be non-identifying.",
      "uniqueItems": true,
      "items": {
        "$ref": "reverse_domain_name.json"
      }
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/ap2_mandate.json",
  "name": "dev.ucp.shopping.ap2_mandate",
  "title": "AP2 Mandate Extension",
  "description": "Extends Checkout with cryptographic mandate support for non-repudiable authorization per the AP2 protocol. Uses embedded signature model with ap2 namespace.",
  "$defs": {
    "merchant_authorization": {
      "title": "Merchant Authorization",
      "description": "JWS Detached Content signature (RFC 7515 Appendix F) over the checkout response body (excluding ap2 field). Format: `<base64url-header>..<base64url-signature>`. The header MUST contain 'alg' (ES256/ES384/ES512) and 'kid' claims. The signature covers both the header and JCS-canonicalized checkout payload.",
      "type": "string",
      "pattern": "^[A-Za-z0-9_-]+\\.\\.[A-Za-z0-9_-]+$"
    },
    "checkout_mandate": {
      "title": "Checkout Mandate",
      "description": "SD-JWT+kb credential in `ap2.checkout_mandate`. Proving user authorization for the checkout. Contains the full checkout including `ap2.merchant_authorization`.",
      "type": "string",
      "pattern": "^[A-Za-z0-9_-]+\\.[A-Za-z0-9_-]*\\.[A-Za-z0-9_-]+(~[A-Za-z0-9_-]+)*$"
    },
    "ap2_with_merchant_authorization": {
      "type": "object",
      "description": "AP2 extension data including merchant authorization.",
      "properties": {
        "merchant_authorization": {
          "$ref": "#/$defs/merchant_authorization",
          "description": "Merchant's signature proving checkout terms are authentic.",
          "ucp_request": "omit"
        }
      }
    },
    "ap2_with_checkout_mandate": {
      "type": "object",
      "description": "AP2 extension data including checkout mandate.",
      "properties": {
        "checkout_mandate": {
          "$ref": "#/$defs/checkout_mandate",
          "description": "SD-JWT+kb proving user authorized this checkout.",
          "ucp_request": {
            "create": "omit",
            "update": "omit",
            "complete": "required"
          }
        }
      }
    },
    "dev.ucp.shopping.checkout": {
      "title": "Checkout with AP2 Mandate",
      "description": "Checkout extended with AP2 mandate support.",
      "allOf": [
        {
          "$ref": "checkout.json"
        },
        {
          "type": "object",
          "properties": {
            "ap2": {
              "allOf": [
                {
                  "$ref": "#/$defs/ap2_with_merchant_authorization"
                },
                {
                  "$ref": "#/$defs/ap2_with_checkout_mandate"
                }
              ],
              "ucp_request": {
                "create": "omit",
                "update": "omit",
                "complete": "required"
              }
            }
          }
        }
      ]
    },
    "error_code": {
      "title": "AP2 Error Code",
      "description": "Error codes specific to AP2 mandate verification.",
      "type": "string",
      "enum": [
        "mandate_required",
        "agent_missing_key",
        "mandate_invalid_signature",
        "mandate_expired",
        "mandate_scope_mismatch",
        "merchant_authorization_invalid",
        "merchant_authorization_missing"
      ]
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/checkout.json",
  "name": "dev.ucp.shopping.checkout",
  "title": "Checkout",
  "description": "Base checkout schema. Extensions compose onto this using allOf.",
  "type": "object",
  "required": [
    "ucp",
    "id",
    "line_items",
    "status",
    "currency",
    "totals",
    "links"
  ],
  "additionalProperties": true,
  "properties": {
    "ucp": {
      "$ref": "../ucp.json#/$defs/response_checkout_schema",
      "ucp_request": "omit"
    },
    "id": {
      "type": "string",
      "description": "Unique identifier of the checkout session.",
      "ucp_request": "omit"
    },
    "line_items": {
      "type": "array",
      "items": {
        "$ref": "types/line_item.json"
      },
      "description": "List of line items being checked out.",
      "ucp_request": {
        "create": "required",
        "update": "required",
        "complete": "omit"
      }
    },
    "buyer": {
      "$ref": "types/buyer.json",
      "description": "Representation of the buyer.",
      "ucp_request": {
        "create": "optional",
        "update": "optional",
        "complete": "omit"
      }
    },
    "context": {
      "$ref": "types/context.json",
      "ucp_request": {
        "create": "optional",
        "update": "optional",
        "complete": "omit"
      }
    },
    "signals": {
      "$ref": "types/signals.json",
      "ucp_request": "optional"
    },
    "attribution": {
      "$ref": "types/attribution.json",
      "ucp_request": "optional"
    },
    "status": {
      "type": "string",
      "enum": [
        "incomplete",
        "requires_escalation",
        "ready_for_complete",
        "complete_in_progress",
        "completed",
        "canceled"
      ],
      "description": "Checkout state indicating the current phase and required action. See Checkout Status lifecycle documentation for state transition details.",
      "ucp_request": "omit"
    },
    "currency": {
      "type": "string",
      "description": "ISO 4217 currency code reflecting the merchant's market determination. Derived from address, context, and geo IP—buyers provide signals, merchants determine currency.",
      "ucp_request": "omit"
    },
    "totals": {
      "$ref": "types/totals.json",
      "description": "Different cart totals.",
      "ucp_request": "omit"
    },
    "messages": {
      "type": "array",
      "items": {
        "$ref": "types/message.json"
      },
      "description": "List of messages with error and info about the checkout session state.",
      "ucp_request": "omit"
    },
    "links": {
      "type": "array",
      "items": {
        "$ref": "types/link.json"
      },
      "description": "Links to be displayed by the platform (Privacy Policy, TOS). Mandatory for legal compliance.",
      "ucp_request": "omit"
    },
    "expires_at": {
      "type": "string",
      "format": "date-time",
      "description": "RFC 3339 expiry timestamp. Default TTL is 6 hours from creation if not sent.",
      "ucp_request": "omit"
    },
    "continue_url": {
      "type": "string",
      "format": "uri",
      "description": "URL for checkout handoff and session recovery. MUST be provided when status is requires_escalation. See specification for format and availability requirements.",
      "ucp_request": "omit"
    },
    "payment": {
      "$ref": "payment.json",
      "ucp_request": {
        "create": "optional",
        "update": "optional",
        "complete": "required"
      }
    },
    "order": {
      "$ref": "types/order_confirmation.json",
      "description": "Details about an order created for this checkout session.",
      "ucp_request": "omit"
    }
  }
}

