{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/types/context.json",
  "title": "Context",
  "description": "Provisional buyer signals for relevance and localization—not authoritative data. Businesses SHOULD use these values when verified inputs (e.g., shipping address) are absent, and MAY ignore or down-rank them if inconsistent with higher-confidence signals (authenticated account, risk detection) or regulatory constraints (export controls). Eligibility and policy enforcement MUST occur at checkout time using binding transaction data. Context SHOULD be non-identifying and can be disclosed progressively—coarse signals early, finer resolution as the session progresses. Higher-resolution data (shipping address, billing address) supersedes context.",
  "type": "object",
  "additionalProperties": true,
  "properties": {
    "address_country": {
      "type": "string",
      "description": "The country. Recommended to be in 2-letter ISO 3166-1 alpha-2 format, for example \"US\". For backward compatibility, a 3-letter ISO 3166-1 alpha-3 country code such as \"SGP\" or a full country name such as \"Singapore\" can also be used. Optional hint for market context (currency, availability, pricing)—higher-resolution data (e.g., shipping address) supersedes this value."
    },
    "address_region": {
      "type": "string",
      "description": "The region in which the locality is, and which is in the country. For example, California or another appropriate first-level Administrative division. Optional hint for progressive localization—higher-resolution data (e.g., shipping address) supersedes this value."
    },
    "postal_code": {
      "type": "string",
      "description": "The postal code. For example, 94043. Optional hint for regional refinement—higher-resolution data (e.g., shipping address) supersedes this value."
    },
    "intent": {
      "type": "string",
      "description": "Background context describing buyer's intent (e.g., 'looking for a gift under $50', 'need something durable for outdoor use'). Informs relevance, recommendations, and personalization."
    },
    "language": {
      "type": "string",
      "description": "Preferred language for content. Use IETF BCP 47 language tags (e.g., 'en', 'fr-CA', 'zh-Hans'). For REST, equivalent to Accept-Language header—platforms SHOULD fall back to Accept-Language when this field is absent; when provided, overrides Accept-Language. Businesses MAY return content in a different language if unavailable."
    },
    "currency": {
      "type": "string",
      "description": "Preferred currency (ISO 4217, e.g., 'EUR', 'USD'). Businesses determine presentment currency from context and authoritative signals; this hint MAY inform selection in multi-currency markets. Also serves as the denomination for price filter values — platforms SHOULD include this field when sending price filters. Response prices include explicit currency confirming the resolution."
    },
    "eligibility": {
      "type": "array",
      "description": "Buyer claims about eligible benefits such as loyalty membership, payment instrument perks, and similar. Recognized claims MAY inform the Business response (e.g., member-only product availability, adjusted pricing in catalog, provisional discounts at cart or checkout). Businesses MUST ignore unrecognized values without error. Values MUST use reverse-domain naming (e.g., 'com.example.loyalty_gold', 'org.school.student') and MUST be non-identifying.",
      "uniqueItems": true,
      "items": {
        "$ref": "reverse_domain_name.json"
      }
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/capability.json",
  "title": "UCP Capability",
  "description": "Schema for UCP capabilities and extensions. Extensions are capabilities with an 'extends' field. Uses reverse-domain naming for governance.",

  "$defs": {
    "base": {
      "allOf": [
        { "$ref": "ucp.json#/$defs/entity" },
        {
          "type": "object",
          "properties": {
            "extends": {
              "oneOf": [
                {
                  "type": "string",
                  "pattern": "^[a-z][a-z0-9]*(?:\\.[a-z][a-z0-9_]*)+$"
                },
                {
                  "type": "array",
                  "items": {
                    "type": "string",
                    "pattern": "^[a-z][a-z0-9]*(?:\\.[a-z][a-z0-9_]*)+$"
                  },
                  "minItems": 1
                }
              ],
              "description": "Parent capability(s) this extends. Present for extensions, absent for root capabilities. Use array for multi-parent extensions."
            }
          }
        }
      ]
    },

    "platform_schema": {
      "title": "Capability (Platform Schema)",
      "description": "Full capability declaration for platform-level discovery. Includes spec/schema URLs for agent fetching.",
      "allOf": [{ "$ref": "#/$defs/base" }, { "required": ["spec", "schema"] }]
    },

    "business_schema": {
      "title": "Capability (Business Schema)",
      "description": "Capability configuration for business/merchant level. May include business-specific config overrides.",
      "allOf": [{ "$ref": "#/$defs/base" }]
    },

    "response_schema": {
      "title": "Capability (Response Schema)",
      "description": "Capability reference in responses. Only name/version required to confirm active capabilities.",
      "allOf": [{ "$ref": "#/$defs/base" }]
    }
  }
}

