{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/ucp.json",
  "title": "UCP Metadata",
  "description": "Protocol metadata for discovery profiles and responses. Uses slim schema pattern with context-specific required fields.",

  "$defs": {
    "version": {
      "type": "string",
      "pattern": "^\\d{4}-\\d{2}-\\d{2}$",
      "description": "UCP version in YYYY-MM-DD format."
    },

    "version_constraint": {
      "type": "object",
      "description": "Version range requirement with minimum and optional maximum.",
      "properties": {
        "min": {
          "$ref": "#/$defs/version",
          "description": "Minimum required version (inclusive)."
        },
        "max": {
          "$ref": "#/$defs/version",
          "description": "Maximum compatible version (inclusive). When absent, no upper bound."
        }
      },
      "required": ["min"],
      "additionalProperties": true
    },

    "requires": {
      "type": "object",
      "description": "Version requirements for extension schemas. Declares minimum (and optionally maximum) protocol and capability versions needed for correct operation.",
      "properties": {
        "protocol": {
          "$ref": "#/$defs/version_constraint",
          "description": "Required protocol version."
        },
        "capabilities": {
          "type": "object",
          "description": "Required capability versions, keyed by capability name. Keys must be a subset of the extension's $defs keys.",
          "propertyNames": { "$ref": "shopping/types/reverse_domain_name.json" },
          "additionalProperties": { "$ref": "#/$defs/version_constraint" }
        }
      },
      "additionalProperties": true
    },

    "entity": {
      "type": "object",
      "description": "Shared foundation for all UCP entities.",
      "required": ["version"],
      "properties": {
        "version": {
          "$ref": "#/$defs/version",
          "description": "Entity version in YYYY-MM-DD format."
        },
        "spec": {
          "type": "string",
          "format": "uri",
          "description": "URL to human-readable specification document."
        },
        "schema": {
          "type": "string",
          "format": "uri",
          "description": "URL to JSON Schema defining this entity's structure and payloads."
        },
        "id": {
          "type": "string",
          "description": "Unique identifier for this entity instance. Used to disambiguate when multiple instances exist."
        },
        "config": {
          "type": "object",
          "description": "Entity-specific configuration. Structure defined by each entity's schema.",
          "additionalProperties": true
        }
      }
    },

    "base": {
      "description": "Base UCP metadata with shared properties for all schema types.",
      "type": "object",
      "required": ["version"],
      "properties": {
        "version": { "$ref": "#/$defs/version" },
        "status": {
          "type": "string",
          "enum": ["success", "error"],
          "default": "success",
          "description": "Application-level status of the UCP operation."
        },
        "services": {
          "type": "object",
          "description": "Service registry keyed by reverse-domain name.",
          "propertyNames": { "$ref": "shopping/types/reverse_domain_name.json" },

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/fulfillment.json",
  "name": "dev.ucp.shopping.fulfillment",
  "title": "Fulfillment Extension",
  "description": "Extends Checkout with fulfillment support using methods, destinations, and groups.",
  "$defs": {
    "fulfillment_option": {
      "$ref": "types/fulfillment_option.json"
    },
    "fulfillment_group": {
      "$ref": "types/fulfillment_group.json"
    },
    "fulfillment_method": {
      "$ref": "types/fulfillment_method.json"
    },
    "fulfillment_available_method": {
      "$ref": "types/fulfillment_available_method.json"
    },
    "fulfillment": {
      "$ref": "types/fulfillment.json"
    },
    "dev.ucp.shopping.checkout": {
      "title": "Checkout with Fulfillment",
      "description": "Checkout extended with hierarchical fulfillment.",
      "allOf": [
        {
          "$ref": "checkout.json"
        },
        {
          "type": "object",
          "properties": {
            "fulfillment": {
              "$ref": "#/$defs/fulfillment",
              "description": "Fulfillment details.",
              "ucp_request": {
                "create": "optional",
                "update": "optional",
                "complete": "omit"
              }
            }
          }
        }
      ]
    },
    "dev.ucp.shopping.fulfillment": {
      "platform_schema": {
        "title": "Fulfillment Capability (Platform)",
        "description": "Platform-level fulfillment capability configuration",
        "allOf": [
          {
            "$ref": "../capability.json#/$defs/platform_schema"
          },
          {
            "properties": {
              "config": {
                "$ref": "types/platform_fulfillment_config.json",
                "description": "Platform fulfillment configuration"
              }
            }
          }
        ]
      },
      "business_schema": {
        "title": "Fulfillment Capability (Business)",
        "description": "Business-level fulfillment capability configuration",
        "allOf": [
          {
            "$ref": "../capability.json#/$defs/business_schema"
          },
          {
            "properties": {
              "config": {
                "$ref": "types/business_fulfillment_config.json",
                "description": "Business fulfillment configuration"
              }
            }
          }
        ]
      }
    }
  },
  "embedded": {
    "delegations": [
      "fulfillment.address_change"
    ],
    "methods": {
      "ec.fulfillment.change": {
        "name": "ec.fulfillment.change",
        "summary": "Fulfillment details changed",
        "description": "Merchant notifies host that checkout.fulfillment has changed (shipping method selected, delivery options updated).",
        "params": [
          {
            "name": "checkout",
            "required": true,
            "schema": {
              "$ref": "checkout.json",
              "description": "Current checkout state with updated fulfillment."
