          }
        ]
      },
      "ec.fulfillment.address_change_request": {
        "name": "ec.fulfillment.address_change_request",
        "summary": "Request address change",
        "description": "Merchant requests host to present address selection UI for a shipping fulfillment method.",
        "params": [
          {
            "name": "checkout",
            "required": true,
            "schema": {
              "$ref": "checkout.json",
              "description": "Current checkout state with fulfillment details."
            }
          }
        ],
        "result": {
          "name": "addressChangeResult",
          "schema": {
            "oneOf": [
              {
                "type": "object",
                "description": "Checkout state after address selection.",
                "required": ["ucp", "checkout"],
                "properties": {
                  "ucp": { "$ref": "../ucp.json#/$defs/success" },
                  "checkout": {
                    "type": "object",
                    "description": "Partial checkout update with fulfillment address selection.",
                    "properties": {
                      "fulfillment": {
                        "$ref": "types/fulfillment.json",
                        "description": "Updated fulfillment with new selected destination and destinations."
                      }
                    }
                  }
                }
              },
              {
                "$ref": "types/error_response.json"
              }
            ]
          }
        }
      }
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/shopping/discount.json",
  "name": "dev.ucp.shopping.discount",
  "title": "Discount Extension",
  "description": "Extends Cart and Checkout with discount support, including discount codes, automatic discounts, and eligibility-triggered provisional discounts.",
  "$defs": {
    "allocation": {
      "type": "object",
      "description": "Breakdown of how a discount amount was allocated to a specific target.",
      "required": [
        "path",
        "amount"
      ],
      "properties": {
        "path": {
          "type": "string",
          "description": "JSONPath to the allocation target (e.g., '$.line_items[0]', '$.totals.shipping')."
        },
        "amount": {
          "$ref": "types/amount.json",
          "description": "Amount allocated to this target in ISO 4217 minor units."
        }
      }
    },
    "applied_discount": {
      "type": "object",
      "description": "A discount that was successfully applied.",
      "required": [
        "title",
        "amount"
      ],
      "properties": {
        "code": {
          "type": "string",
          "description": "The discount code. Omitted for automatic discounts."
        },
        "title": {
          "type": "string",
          "description": "Human-readable discount name (e.g., 'Summer Sale 20% Off')."
        },
        "amount": {
          "$ref": "types/amount.json",
          "description": "Total discount amount in ISO 4217 minor units."
        },
        "automatic": {
          "type": "boolean",
          "default": false,
          "description": "True if applied automatically by merchant rules (no code required)."
        },
        "method": {
          "type": "string",
          "enum": [
            "each",
            "across"
          ],
          "description": "Allocation method. 'each' = applied independently per item. 'across' = split proportionally by value."
        },
        "priority": {
          "type": "integer",
          "minimum": 1,
          "description": "Stacking order for discount calculation. Lower numbers applied first (1 = first)."
        },
        "provisional": {
          "type": "boolean",
          "default": false,
          "description": "True if this discount requires additional verification."
        },
        "eligibility": {
          "$ref": "types/reverse_domain_name.json",
          "description": "The eligibility claim accepted by the Business for this discount. Corresponds to a value from context.eligibility. Omitted for code-based and non-eligibility automatic discounts."
        },
        "allocations": {
          "type": "array",
          "items": {
            "$ref": "#/$defs/allocation"
          },
          "description": "Breakdown of where this discount was allocated. Sum of allocation amounts equals total amount."
        }
      }
    },
    "discounts_object": {
      "type": "object",
      "description": "Discount codes input and applied discounts output.",
      "properties": {
        "codes": {
          "type": "array",
          "items": {
            "type": "string"
          },
          "description": "Discount codes to apply. Case-insensitive. Replaces previously submitted codes. Send empty array to clear."
        },
        "applied": {
          "type": "array",
          "items": {
            "$ref": "#/$defs/applied_discount"
          },
          "description": "Discounts successfully applied (code-based and automatic).",
          "ucp_request": "omit"
        }
      }
    },
    "dev.ucp.shopping.cart": {
      "title": "Cart with Discount",
      "description": "Cart extended with discount capability.",
      "allOf": [
        {
          "$ref": "cart.json"
        },
        {
          "type": "object",
          "properties": {
            "discounts": {
              "$ref": "#/$defs/discounts_object",
              "ucp_request": {
                "create": "optional",
                "update": "optional"
              }
            }
          }
        }
      ]
    },
    "dev.ucp.shopping.checkout": {
      "title": "Checkout with Discount",
      "description": "Checkout extended with discount capability.",
      "allOf": [
        {
          "$ref": "checkout.json"
        },
        {
          "type": "object",
          "properties": {
            "discounts": {
              "$ref": "#/$defs/discounts_object",
              "ucp_request": {
                "create": "optional",
                "update": "optional",
                "complete": "omit"
              }
            }
          }
        }
      ]
    }
  }
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://ucp.dev/schemas/capability.json",
  "title": "UCP Capability",
  "description": "Schema for UCP capabilities and extensions. Extensions are capabilities with an 'extends' field. Uses reverse-domain naming for governance.",

  "$defs": {
    "base": {
      "allOf": [
        { "$ref": "ucp.json#/$defs/entity" },
        {
          "type": "object",
          "properties": {
            "extends": {
              "oneOf": [
                {
                  "type": "string",
                  "pattern": "^[a-z][a-z0-9]*(?:\\.[a-z][a-z0-9_]*)+$"
                },
                {
                  "type": "array",
                  "items": {
                    "type": "string",
                    "pattern": "^[a-z][a-z0-9]*(?:\\.[a-z][a-z0-9_]*)+$"
                  },
                  "minItems": 1
                }
              ],
              "description": "Parent capability(s) this extends. Present for extensions, absent for root capabilities. Use array for multi-parent extensions."
            }
          }
        }
      ]
    },

    "platform_schema": {
      "title": "Capability (Platform Schema)",
      "description": "Full capability declaration for platform-level discovery. Includes spec/schema URLs for agent fetching.",
      "allOf": [{ "$ref": "#/$defs/base" }, { "required": ["spec", "schema"] }]
    },

    "business_schema": {
      "title": "Capability (Business Schema)",
      "description": "Capability configuration for business/merchant level. May include business-specific config overrides.",
      "allOf": [{ "$ref": "#/$defs/base" }]
    },

    "response_schema": {
      "title": "Capability (Response Schema)",
      "description": "Capability reference in responses. Only name/version required to confirm active capabilities.",
      "allOf": [{ "$ref": "#/$defs/base" }]
    }
  }
}

